useEffect(() => {
  if (!sortRefreshAlignPendingRef.current) return undefined

  sortRefreshAlignPendingRef.current = false
  clearSortRefreshAlignHandles()

  const startUserScrollTs = (() => {
    try { return Number(window.__forumUserScrollTs || 0) } catch { return 0 }
  })()

  let cancelled = false
  const scheduleAlign = (attempt = 0) => {
    if (cancelled) return
    const currentUserScrollTs = (() => {
      try { return Number(window.__forumUserScrollTs || 0) } catch { return 0 }
    })()
    if (attempt > 0 && currentUserScrollTs > startUserScrollTs) return
    const aligned = !!runSortRefreshAlignment()
    if (aligned) return
    if (attempt >= 12) return
    const delay = attempt <= 1 ? 72 : (attempt <= 6 ? 130 : 200)
    const timerId = setTimeout(() => scheduleAlign(attempt + 1), delay)
    sortRefreshAlignTimersRef.current.push(timerId)
  }

  try {
    const rafA = requestAnimationFrame(() => {
      const rafB = requestAnimationFrame(() => scheduleAlign(0))
      sortRefreshAlignRafsRef.current.push(rafB)
    })
    sortRefreshAlignRafsRef.current.push(rafA)
  } catch {
    const timerId = setTimeout(() => scheduleAlign(0), 0)
    sortRefreshAlignTimersRef.current.push(timerId)
  }

  return () => {
    cancelled = true
    clearSortRefreshAlignHandles()
  }
}, [clearSortRefreshAlignHandles, contentRefreshToken, runSortRefreshAlignment])

React.useEffect(() => {
  const a = audioRef.current
  if (!a) return

  setPlaying(false)
  setDur(0)
  setPos(0)
  draggingRef.current = false
  stopRaf()
  stopDurationPoll()

  try {
    a.pause?.()
  } catch {}
  try {
    a.currentTime = 0
  } catch {}
  try {
    a.playbackRate = rateRef.current
  } catch {}

  const onLoaded = () => syncAudioMetrics(a)
  const onPlay = () => {
    setPlaying(true)
    syncAudioMetrics(a)
    startRaf()
  }
  const onPause = () => {
    setPlaying(false)
    stopRaf()
  }
  const onEnded = () => {
    setPlaying(false)
    stopRaf()
    setPos(0)
  }
  const onTimeUpdate = () => syncAudioMetrics(a)

  a.addEventListener('loadedmetadata', onLoaded)
  a.addEventListener('loadeddata', onLoaded)
  a.addEventListener('canplay', onLoaded)
  a.addEventListener('durationchange', onLoaded)
  a.addEventListener('progress', onLoaded)
  a.addEventListener('timeupdate', onTimeUpdate)
  a.addEventListener('play', onPlay)
  a.addEventListener('pause', onPause)
  a.addEventListener('ended', onEnded)
  durationPollRef.current = window.setInterval(() => syncAudioMetrics(a), 350)
  syncAudioMetrics(a)

  return () => {
    a.removeEventListener('loadedmetadata', onLoaded)
    a.removeEventListener('loadeddata', onLoaded)
    a.removeEventListener('canplay', onLoaded)
    a.removeEventListener('durationchange', onLoaded)
    a.removeEventListener('progress', onLoaded)
    a.removeEventListener('timeupdate', onTimeUpdate)
    a.removeEventListener('play', onPlay)
    a.removeEventListener('pause', onPause)
    a.removeEventListener('ended', onEnded)
    stopRaf()
    stopDurationPoll()
  }
}, [src, startRaf, stopDurationPoll, stopRaf, syncAudioMetrics])

React.useEffect(() => {
  if (!qcastFxProfile.viz) return undefined

  const audio = audioRef.current
  const canvas = canvasRef.current
  if (!audio || !canvas) return undefined

  const st = waRef.current
  const ctx2d = canvas.getContext('2d', { alpha: true })
  if (!ctx2d) return undefined
  st.ctx2d = ctx2d

  const resize = () => {
    try {
      const host = hostRef.current
      const rect = host?.getBoundingClientRect?.()
      const w = Math.max(32, Math.round(rect?.width || 0))
      const h = Math.max(32, Math.round(rect?.height || 0))
      const dpr = Math.min(2, Math.max(1, Number(window.devicePixelRatio || 1)))
      st.dpr = dpr
      st.w = w
      st.h = h
      canvas.width = Math.round(w * dpr)
      canvas.height = Math.round(h * dpr)
      canvas.style.width = `${w}px`
      canvas.style.height = `${h}px`
      ctx2d.setTransform(dpr, 0, 0, dpr, 0, 0)
    } catch {}
  }

  resize()

  try {
    st.ro?.disconnect?.()
  } catch {}
  try {
    if (typeof ResizeObserver !== 'undefined') {
      st.ro = new ResizeObserver(() => resize())
      if (hostRef.current) st.ro.observe(hostRef.current)
    }
  } catch {}

  const paint = () => {
    st.raf = 0
    try {
      if (!hostRef.current || !ctx2d) return
      const w = st.w || 1
      const h = st.h || 1
      ctx2d.clearRect(0, 0, w, h)

      if (!isPlaying || !st.analyser || !st.data) return

      st.analyser.getByteFrequencyData(st.data)

      const bars = 32
      const gap = 4
      const barW = Math.max(3, Math.floor((w - gap * (bars - 1)) / bars))
      const step = Math.max(1, Math.floor(st.data.length / bars))
      const baseY = h - 14

      for (let i = 0; i < bars; i++) {
        const sample = st.data[Math.min(st.data.length - 1, i * step)] || 0
        const amp = sample / 255
        const bh = Math.max(6, Math.round(amp * (h * 0.34)))
        const x = i * (barW + gap)
        const y = baseY - bh

        ctx2d.fillStyle = i % 2 === 0 ? 'rgba(97, 214, 255, 0.18)' : 'rgba(255, 110, 214, 0.14)'
        ctx2d.fillRect(x, y, barW, bh)

        ctx2d.fillStyle = i % 2 === 0 ? 'rgba(125, 228, 255, 0.82)' : 'rgba(255, 156, 224, 0.72)'
        ctx2d.fillRect(x, y + Math.max(0, bh - 10), barW, Math.min(10, bh))
      }

      const glow = ctx2d.createLinearGradient(0, 0, 0, h)
      glow.addColorStop(0, 'rgba(84, 202, 255, 0.10)')
      glow.addColorStop(0.55, 'rgba(32, 110, 168, 0.04)')
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)')
      ctx2d.fillStyle = glow
      ctx2d.fillRect(0, 0, w, h)
    } catch {}
  }

  const tick = () => {
    paint()
    st.raf = requestAnimationFrame(tick)
  }

  st.raf = requestAnimationFrame(tick)

  return () => {
    try {
      if (st.raf) cancelAnimationFrame(st.raf)
    } catch {}
    st.raf = 0
    try {
      st.ro?.disconnect?.()
    } catch {}
    st.ro = null
    try {
      ctx2d.clearRect(0, 0, st.w || 0, st.h || 0)
    } catch {}
  }
}, [isPlaying, qcastFxProfile.viz])
